use std::io::{self,Read};fn r(s:&str,k:i32)->String{if k<=1{return s.to_string()}let mut c=[0;26];let mut last=[-1000000000;26];for b in s.bytes(){c[(b-b'a')as usize]+=1;}let mut out=String::new();for p in 0..s.len() as i32{let mut best:i32=-1;for i in 0..26{if c[i]>0&&p-last[i]>=k&&(best<0||c[i]>c[best as usize]){best=i as i32}}if best<0{return String::new()}let b=best as usize;out.push((b'a'+b as u8)as char);c[b]-=1;last[b]=p;}out}fn main(){let mut x=String::new();io::stdin().read_to_string(&mut x).unwrap();let d:Vec<&str>=x.split_whitespace().collect();if d.is_empty(){return};let mut idx=0;let t:usize=d[idx].parse().unwrap();idx+=1;let mut out=Vec::new();for _ in 0..t{let s=d[idx];let k:i32=d[idx+1].parse().unwrap();idx+=2;out.push(format!("\"{}\"",r(s,k)));}print!("{}",out.join("\n\n"));}
